    19→@freezed
    20→abstract class Team with _$Team {
    21→  const Team._();
    22→
    23→  @JsonSerializable(
    24→    explicitToJson: true,
    25→    fieldRename: Constants.modelFieldRename,
    26→  )
    27→  const factory Team({
    28→    @Default(null) String? id,
    29→    @Default(null) String? name,
    30→    @Default(null) String? ownerUserId,
    31→    @Default(TeamType.multiple) TeamType teamType,
    32→    @Default(null) DateTime? createdAt, // assumes UTC
    33→    @Default(null) DateTime? updatedAt, // assumes UTC
    34→    @Default(null) DateTime? teamPlanCancelAt,
    35→    @Default(null) DateTime? teamPlanDowngradeAt,
    36→    @Default(null) String? imageUrl,
    37→    @Default(null) TeamPlan? teamPlan,
    38→    @Default(null) TeamPlan? nextTeamPlan,
    39→    @Default(null) String? presignedImageUrl,
    40→    @Default(null) String? billingFailureReason,
    41→    @Default(null) String? downgradePlanId,
    42→    @Default(null) Item? item,
    43→  }) = _Team;
    44→
    45→  factory Team.fromJson(Map<String, dynamic> json) => _$TeamFromJson(json);
    46→
    47→  bool get isSingleUserTeam => teamType == TeamType.single;
    48→
    49→  /// ボール解析の使用量（TeamPlan + Item の合算）
    50→  int get ballUsage {
    51→    final planUsage =
    52→        (teamPlan?.withinPeriod ?? false) ? teamPlan?.currentUsage ?? 0 : 0;
    53→    final itemUsage = item?.ballUsage ?? 0;
    54→    return planUsage + itemUsage;
    55→  }
    56→
    57→  /// AI コーチの使用量（TeamPlan + Item の合算）
    58→  int get aiCoachUsage {
    59→    final planUsage = (teamPlan?.withinPeriod ?? false)
    60→        ? teamPlan?.currentAiCoachUsage ?? 0
    61→        : 0;
    62→    final itemUsage = item?.aiCoachUsage ?? 0;
    63→    return planUsage + itemUsage;
    64→  }
    65→
    66→  /// ボール解析の上限数（Plan + Item の合算）
    67→  int get maxBalls {
    68→    final planMax =
    69→        (teamPlan?.withinPeriod ?? false) ? teamPlan?.plan?.maxBalls ?? 0 : 0;
    70→    final itemMax = item?.ballAvailableCount ?? 0;
    71→    return planMax + itemMax;
    72→  }
    73→
    74→  /// AI コーチの上限数（Plan + Item の合算）
    75→  int get maxAICoachCount {
    76→    final planMax = (teamPlan?.withinPeriod ?? false)
    77→        ? teamPlan?.plan?.maxAiCoachs ?? 0
    78→        : 0;
    79→    final itemMax = item?.aiCoachAvailableCount ?? 0;
    80→    return planMax + itemMax;
    81→  }
    82→
    83→  /// プランの契約・有効期限状態
    84→  TeamPlanStatus get teamPlanStatus {
    85→    // 1. teamPlanがnullまたはisActive!=trueの場合
    86→    if (teamPlan == null || teamPlan!.isActive != true) {
    87→      return TeamPlanStatus.noContract;
    88→    }
    89→
    90→    // 2. 期限切れか
    91→    final now = resolveTeamPlanNow();
    92→    final endDate = teamPlan!.endDate;
    93→    // 以下の場合は nextTeamPlan の endDate を使用する
    94→    // 1. nextTeamPlan が存在
    95→    // 2. nextTeamPlan の isPendingActivation が true
    96→    // 3. teamPlan の endDate が nextTeamPlan の startDate と同じ (連続してプランを継続している)
    97→    final effectiveEndDate = (nextTeamPlan != null &&
    98→            nextTeamPlan!.isPendingActivation == true &&
    99→            endDate == nextTeamPlan!.startDate)
   100→        ? nextTeamPlan!.endDate
   101→        : endDate;
   102→    final isExpired =
   103→        effectiveEndDate != null && effectiveEndDate.isBefore(now);
   104→    if (isExpired) {
   105→      if (nextTeamPlan != null && nextTeamPlan!.isPendingActivation == true) {
   106→        return TeamPlanStatus.nextPlanPending;
   107→      }
   108→      return TeamPlanStatus.expired;
   109→    }
   110→
   111→    // 3. 期限警告（30日以内）
   112→    if (effectiveEndDate != null) {
   113→      final oneMonthLater = now.add(const Duration(days: 30));
   114→      if (effectiveEndDate.isAfter(now) &&
   115→          effectiveEndDate.isBefore(oneMonthLater)) {
   116→        return TeamPlanStatus.expiringSoon;
   117→      }
   118→    }
   119→
   120→    // 4. 問題なし
   121→    return TeamPlanStatus.ok;
   122→  }
   123→
   124→  /// ボール解析の使用量状態
   125→  BallAnalysisUsageStatus get ballAnalysisUsageStatus {
   126→    final usage = ballUsage;
   127→    final maxUsage = maxBalls;
   128→
   129→    // 上限到達
   130→    if (usage >= maxUsage) {
   131→      return BallAnalysisUsageStatus.limitReached;
   132→    }
   133→
   134→    // 上限接近（90%以上）
   135→    if (usage >= (maxUsage * 0.9).floor()) {
   136→      return BallAnalysisUsageStatus.limitApproaching;
   137→    }
   138→
   139→    // 正常
   140→    return BallAnalysisUsageStatus.ok;
   141→  }
   142→
   143→  /// AI コーチの使用量状態
   144→  AICoachUsageStatus get aiCoachUsageStatus {
   145→    final usage = aiCoachUsage;
   146→    final maxUsage = maxAICoachCount;
   147→
   148→    // 上限到達
   149→    if (usage >= maxUsage) {
   150→      return AICoachUsageStatus.limitReached;
   151→    }
   152→
   153→    // 上限接近（90%以上）
   154→    if (usage >= (maxUsage * 0.9).floor()) {
   155→      return AICoachUsageStatus.limitApproaching;
   156→    }
   157→
   158→    // 正常
   159→    return AICoachUsageStatus.ok;
   160→  }
   161→
   162→  /// ボール解析が実行可能かどうか
   163→  bool get canAnalyzeBall {
   164→    return ballAnalysisUsageStatus.canAnalyze;
   165→  }
   166→
   167→  /// AI コーチが利用可能かどうか
   168→  bool get canUseAiCoach {
   169→    return aiCoachUsageStatus.canUseAiCoach;
   170→  }
   171→}
   172→
   173→/// チームプランの契約・有効期限に関する状態
   174→enum TeamPlanStatus {
   175→  // アプリ利用不可
   176→  noContract, // 有料プラン契約なし
   177→  nextPlanPending, // 次回プランが保留中
   178→  expired, // 期限切れ
   179→
   180→  // アプリ利用可（警告あり）
   181→  expiringSoon, // 30日以内に期限切れ
   182→
   183→  // アプリ利用可（正常）
   184→  ok,
   185→  ;
   186→
   187→  /// プランが有効かどうか（契約があり、期限内）
   188→  bool get isValid => this == expiringSoon || this == ok;
   189→}
   190→
   191→/// ボール解析の使用量状態
   192→enum BallAnalysisUsageStatus {
   193→  // 解析不可
   194→  limitReached, // 上限到達（currentUsage >= maxBalls）
   195→
   196→  // 解析可（警告あり）
   197→  limitApproaching, // 上限接近（currentUsage >= maxBalls * 0.9）
   198→
   199→  // 解析可（正常）
   200→  ok,
   201→  ;
   202→
   203→  /// 解析実行可能かどうか
   204→  bool get canAnalyze => this == limitApproaching || this == ok;
   205→
   206→  /// 警告を表示すべきかどうか
   207→  bool get shouldWarn => this == limitApproaching;
   208→}
   209→
   210→/// AI コーチの使用量状態
   211→enum AICoachUsageStatus {
   212→  // AI コーチ利用不可
   213→  limitReached, // 上限到達（currentAiCoachUsage >= maxAiCoachs）
   214→
   215→  // AI コーチ利用可（警告あり）
   216→  limitApproaching, // 上限接近（currentAiCoachUsage >= maxAiCoachs * 0.9）
   217→
   218→  // AI コーチ利用可（正常）
   219→  ok,
   220→  ;
   221→
   222→  /// AI コーチ利用可能かどうか
   223→  bool get canUseAiCoach => this == limitApproaching || this == ok;
   224→}
