   577→      const callbackUrl = createSafeCallbackUrl();
   578→      router.replace(`${PAGE_INFO.SIGN_IN.href()}?callbackUrl=${callbackUrl}`);
   579→    }
   580→  }, [loginStatus]);
   581→
   582→  if (loginStatus == 'error' && userError) {
   583→    return (
   584→      <>
   585→        <CriticalError error={userError} />
   586→      </>
   587→    );
   588→  }
   589→
   590→  return currentUser && currentTeam ? (
