   601→      <Button color="error" sx={{ mt: 2 }} variant="contained" onClick={logout}>
   602→        {translate('sign_out')}
   603→      </Button>
   604→    </Box>
   605→  ) : (
   606→    <>
   607→      {
   608→        // nothing to do (waiting initialization)
   609→      }
   610→    </>
   611→  );
   612→}
