import ArrowUpwardIcon from '@mui/icons-material/ArrowUpward';
import WarningIcon from '@mui/icons-material/Warning';
import {
  Box,
  Button,
  Card,
  CardContent,
  Stack,
  Typography,
} from '@mui/material';
import React from 'react';

import { translate } from '@/utils/i18n';

export type PlanStatus =
  | 'upgrade_prompt'
  | 'pre_warning'
  | 'limit_reached'
  | 'billing_failure';

interface PlanStatusCardProps {
  status: PlanStatus;
  open: boolean;
  onUpgrade?: () => void;
}

const getStatusConfig = (status: PlanStatus) => {
  switch (status) {
    case 'upgrade_prompt':
      return {
        title: translate('plan_upgrade_prompt_title'),
        message: translate('plan_upgrade_message'),
        icon: (
          <Box
            sx={{
              width: 48,
              height: 48,
              bgcolor: 'primary.main',
              borderRadius: 1,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              color: 'white',
            }}
          >
            <ArrowUpwardIcon sx={{ fontSize: '1.5rem' }} />
          </Box>
        ),
      };
    case 'pre_warning':
      return {
        title: translate('plan_pre_warning_title'),
        message: translate('plan_pre_warning_message'),
        icon: (
          <Box
            sx={{
              width: 48,
              height: 48,
              bgcolor: 'transparent',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
            }}
          >
            <WarningIcon sx={{ fontSize: '2rem', color: '#FFD700' }} />
          </Box>
        ),
      };
    case 'limit_reached':
      return {
        title: translate('plan_limit_reached_title'),
        message: translate('plan_limit_reached_message'),
        icon: (
          <Box
            sx={{
