            sx={{
              lineHeight: 1.4,
              wordBreak: 'break-word',
              whiteSpace: 'normal',
              textAlign: 'center',
            }}
          >
            {config.message}
          </Typography>

          <Button
            variant="contained"
            color="primary"
            fullWidth
            onClick={onUpgrade}
            sx={{ py: 1, fontWeight: 600 }}
          >
            {status === 'billing_failure'
              ? translate('open_billing_portal')
              : translate('plan_upgrade_button')}
          </Button>
        </Stack>
      </CardContent>
    </Card>
  );
}

