    85→  const searchParams = useSearchParams();
    86→  const [tabValue, setTabValue] = useState<string>(
    87→    searchParams.get('tab') ?? AccountTab,
    88→  );
    89→
    90→  const hasSuperUserReadAccess = User.isAccessible(
    91→    currentUser,
    92→    'all',
    93→    'admin',
    94→    'read',
    95→    false,
    96→  );
    97→
    98→  const tabs = [AccountTab, TeamTab, ChangePasswordTab] as TranslationKey[];
