   213→        sx={{ position: 'absolute', top: 20, right: 20 }}
   214→      >
   215→        <Edit />
   216→      </IconButton>
   217→      <Stack direction="column">
   218→        <Typography sx={{ mb: 3 }} variant="h2">
   219→          {translate('account')}
   220→        </Typography>
   221→        <Grid container spacing={3}>
   222→          <Grid size={{ sm: 6, xs: 12 }}>
   223→            <FormControl fullWidth sx={{ mb: 2 }}>
   224→              <FormLabel>
   225→                <Typography variant="h4">
   226→                  {translate('email')}
   227→                </Typography>
   228→              </FormLabel>
   229→              <Typography>{currentUser.email}</Typography>
   230→            </FormControl>
   231→          </Grid>
   232→          <Grid size={{ sm: 6, xs: 12 }}>
   233→            <FormControl fullWidth sx={{ mb: 2 }}>
