   304→                href={contactFormUrl}
   305→                target="_blank"
   306→                rel="noopener noreferrer"
   307→                fullWidth={isSmallScreen}
   308→                sx={{ flex: 1 }}
   309→              >
   310→                {translate('open_contact_form')}
   311→              </Button>
   312→            )}
   313→          </Stack>
   314→        </Stack>
   315→      </Stack>
   316→    </Paper>
   317→  );
   318→
   319→  const renderTeamTab = () => (
   320→    <Paper
   321→      sx={{
   322→        p: 3,
   323→        position: 'relative',
   324→        overflowWrap: 'break-word',
   325→      }}
   326→    >
   327→      {teams.length >= 2 && (
   328→        <IconButton
   329→          color="primary"
   330→          href={PAGE_INFO.ACCOUNT_EDIT.href(TeamTab)}
   331→          sx={{ position: 'absolute', top: 20, right: 20 }}
