   406→                        >
   407→                          {translate(
   408→                            'apple_subscription_active_notice',
   409→                          )}
   410→                        </Typography>
   411→                      )}
   412→                    </FormControl>
   413→
   414→                    {currentTeam.teamPlan.plan.isPaid && (
   415→                      <>
   416→                        <FormControl fullWidth sx={{ mb: 2 }}>
   417→                          <FormLabel>
   418→                            <Typography variant="h4">
   419→                              {translate('validity_period')}
   420→                            </Typography>
