   501→                    <FormControl fullWidth sx={{ mb: 2 }}>
   502→                      <FormLabel>
   503→                        <Typography variant="h4">
   504→                          {translate('next_validity_period')}
   505→                        </Typography>
   506→                      </FormLabel>
   507→                      <Typography>
