   629→              width={120}
   630→              height={120}
   631→            />
   632→            <Box sx={{ flex: 1, px: 3 }}>
   633→              <Typography variant="h1">
   634→                {currentUser.profile?.username ?? '(No Name)'}
   635→              </Typography>
   636→            </Box>
   637→            <Box>
   638→              <Button
   639→                color="neutral"
   640→                loading={isSubmitting}
   641→                onClick={() => logout()}
   642→              >
   643→                {translate('sign_out')}
   644→              </Button>
   645→            </Box>
   646→          </Stack>
   647→          <Divider sx={{ mt: 2 }} />
   648→        </Box>
   649→        <Tabs sx={{ mb: 2, mt: 4 }} value={tabValue} onChange={handleTabChange}>
