   654→                label={translate(tab)}
   655→                style={{ backgroundColor: 'inherit' }}
   656→                sx={{ px: 2, py: 1 }}
   657→                value={tab}
   658→              />
   659→            );
   660→          })}
   661→        </Tabs>
   662→        {loadError ? (
   663→          <CriticalError error={loadError} />
   664→        ) : (
   665→          <>
   666→            <TabPanel index={AccountTab} value={tabValue}>
