   668→            </TabPanel>
   669→            <TabPanel index={TeamTab} value={tabValue}>
   670→              {renderTeamTab()}
   671→            </TabPanel>
   672→            <TabPanel index={ChangePasswordTab} value={tabValue}>
   673→              {renderChangePasswordTab()}
   674→            </TabPanel>
   675→          </>
   676→        )}
   677→      </Stack>
   678→    </Container>
   679→  );
   680→}
   681→
   682→export default function Page() {
   683→  const currentUser = useSelector((state) => state.user.me);
   684→  const currentTeam = useSelector((state) => state.user.currentTeam);
   685→
   686→  return (
   687→    currentUser &&
   688→    currentTeam && (
   689→      <PageInner currentUser={currentUser} currentTeam={currentTeam} />
   690→    )
   691→  );
   692→}
   693→
   694→Page.getLayout = function getLayout(page: ReactElement) {
   695→  return <ConsoleLayout>{page}</ConsoleLayout>;
   696→};
