import ArrowUpwardIcon from '@mui/icons-material/ArrowUpward';
import WarningIcon from '@mui/icons-material/Warning';
import {
  Box,
  Button,
  Card,
  CardContent,
  Stack,
  Typography,
} from '@mui/material';
import React from 'react';

import { translate } from '@/utils/i18n';

export type PlanStatus =
  | 'upgrade_prompt'
  | 'pre_warning'
  | 'limit_reached'
  | 'billing_failure';

interface PlanStatusCardProps {
  status: PlanStatus;
  open: boolean;
  onUpgrade?: () => void;
  billingFailureReason?: string | null;
}

const getStatusConfig = (
  status: PlanStatus,
  billingFailureReason?: string | null,
) => {
  switch (status) {
    case 'upgrade_prompt':
      return {
        title: translate('plan_upgrade_prompt_title'),
        message: translate('plan_upgrade_message'),
        icon: (
          <Box
            sx={{
              width: 48,
              height: 48,
              bgcolor: 'primary.main',
              borderRadius: 1,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              color: 'white',
            }}
          >
            <ArrowUpwardIcon sx={{ fontSize: '1.5rem' }} />
          </Box>
        ),
      };
    case 'pre_warning':
      return {
        title: translate('plan_pre_warning_title'),
        message: translate('plan_pre_warning_message'),
        icon: (
          <Box
            sx={{
              width: 48,
              height: 48,
              bgcolor: 'transparent',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
            }}
          >
            <WarningIcon sx={{ fontSize: '2rem', color: '#FFD700' }} />
          </Box>
        ),
      };
    case 'limit_reached':
      return {
        title: translate('plan_limit_reached_title'),
        message: translate('plan_limit_reached_message'),
        icon: (
          <Box
            sx={{
              width: 48,
              height: 48,
              bgcolor: 'transparent',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
            }}
          >
            <WarningIcon sx={{ fontSize: '2rem', color: '#FFD700' }} />
          </Box>
        ),
      };
    case 'billing_failure': {
      const messageKey =
        billingFailureReason === 'stripe_payment_failed'
          ? 'payment_failed_stripe'
          : billingFailureReason === 'apple_payment_failed'
          ? 'payment_failed_apple'
          : 'plan_billing_failure_message';
      return {
        title: translate('plan_billing_failure_title'),
        message: translate(messageKey),
        icon: (
          <Box
            sx={{
              width: 48,
              height: 48,
              bgcolor: 'transparent',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
            }}
          >
            <WarningIcon sx={{ fontSize: '2rem', color: '#FFD700' }} />
          </Box>
        ),
      };
    }
  }
};

export default function PlanStatusCard({
  status,
  open,
  onUpgrade,
  billingFailureReason,
}: PlanStatusCardProps) {
  const config = getStatusConfig(status, billingFailureReason);

  if (!open) {
    return null;
  }

  return (
    <Card
      sx={{
        position: 'relative',
        mx: 2,
        mb: 2,
        mt: 1,
        boxShadow: 4,
        borderRadius: 2,
        maxWidth: '100%',
        width: 'calc(100% - 32px)',
        backgroundColor: 'white',
      }}
    >
      <CardContent
        sx={{
          p: 2,
          textAlign: 'center',
          width: '100%',
          boxSizing: 'border-box',
        }}
      >
        <Stack spacing={2} alignItems="center" sx={{ width: '100%' }}>
          {status === 'upgrade_prompt' && (
            <Typography variant="body2" color="primary" sx={{ mb: -1 }}>
              {config.title}
            </Typography>
          )}

          {config.icon}

          <Typography
            variant="body2"
            sx={{
              lineHeight: 1.4,
              wordBreak: 'break-word',
              whiteSpace: 'normal',
              textAlign: 'center',
            }}
          >
            {config.message}
          </Typography>

          <Button
            variant="contained"
            color="primary"
            fullWidth
            onClick={onUpgrade}
            sx={{ py: 1, fontWeight: 600 }}
          >
            {status === 'billing_failure'
              ? translate('open_billing_portal')
              : translate('plan_upgrade_button')}
          </Button>
        </Stack>
      </CardContent>
    </Card>
  );
}

